function linearRing(n,r,e,i){let l=0;var t=n[e-i],a=n[e-i+1];let g=0,R=0;for(;r<e;r+=i){var o=n[r]-t,s=n[r+1]-a;l+=R*o-g*s,g=o,R=s}return l/2}function linearRings(e,i,l,t){let a=0;for(let n=0,r=l.length;n<r;++n){var g=l[n];a+=linearRing(e,i,g,t),i=g}return a}function linearRingss(e,i,l,t){let a=0;for(let n=0,r=l.length;n<r;++n){var g=l[n];a+=linearRings(e,i,g,t),i=g[g.length-1]}return a}export{linearRing,linearRings,linearRingss};